'use strict';

const test = require('node:test');
const assert = require('node:assert/strict');
const { buildEnvelope } = require('../src/job_envelope');
const { contextFromEnvelope } = require('../src/worker_context');

test('an external zero-based delivery remains unsampled', () => {
  assert.deepEqual(
    contextFromEnvelope({ job: { kind: 'sync', id: 's-2' }, attempt: 0, traceSampled: false }),
    { attempt: 0, traceSampled: false },
  );
});

test('local envelope and worker agree on falsy metadata', () => {
  const envelope = buildEnvelope({ kind: 'sync', id: 's-3' }, {
    attempt: 0,
    traceSampled: false,
  });
  assert.deepEqual(contextFromEnvelope(envelope), {
    attempt: 0,
    traceSampled: false,
  });
});
